async (params, browser) => {
  // Search Airbnb listings
  await browser.open(`https://www.airbnb.com/s/${params.location}/homes`)

  // Wait for search results
  await browser.waitForSelector('[itemprop=\'itemListElement\'], [data-testid=\'card-container\'], [data-testid=\'listing-card-title\']', 15000)

  // Let results render
  await browser.wait(3000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll for more listings
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll to load all visible listings
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

