p(function(l) { return parseFloat(l.price_per_night.replace(/[^0-9.]/g, '')) || 0; }).filter(function(p) { return p > 0; }); const avgPrice = prices.length > 0 ? (prices.reduce(function(a, b) { return a + b; }, 0) / prices.length).toFixed(2) : '0'; const minPrice = prices.length > 0 ? Math.min.apply(null, prices) : 0; const maxPrice = prices.length > 0 ? Math.max.apply(null, prices) : 0; return { location: params.location, listing_count: listings.length, price_summary: { average_price_per_night: avgPrice, min_price_per_night: minPrice, max_price_per_night: maxPrice, currency: listings[0] ? listings[0].price_per_night.replace(/[0-9.,\s]/g, '').trim() : '' }, listings: listings }`)

  return price_comparison
}
